var suffix = formats.HasFlag(MetricFormat.UseSymbol)
    ? symbol.Value.ToString()
    : $" {GetPrefixName(symbol.Value, formats)}";

return isNegative ? $"-{valueStr}{suffix}" : $"{valueStr}{suffix}";

